<?php require_once dirname(__DIR__) . '/includes/db.php'; $token=$_GET['token']??''; $ok=false; if($token){ $pdo=db(); $stmt=$pdo->prepare('SELECT * FROM subscribers WHERE unsubscribe_token=?'); $stmt->execute([$token]); if($sub=$stmt->fetch()){ $pdo->prepare('UPDATE subscribers SET status="unsubscribed" WHERE id=?')->execute([$sub['id']]); $pdo->prepare('INSERT INTO unsubscribes (subscriber_id,email,unsubscribe_token,ip_address,user_agent) VALUES (?,?,?,?,?)')->execute([$sub['id'],$sub['email'],$token,client_ip(),substr($_SERVER['HTTP_USER_AGENT']??'',0,255)]); $ok=true; }} ?><!doctype html><html><head><meta name="viewport" content="width=device-width,initial-scale=1"><title>Unsubscribed</title><link rel="stylesheet" href="../assets/admin.css"></head><body><main class="wrap"><div class="card"><h1><?= $ok?'You are unsubscribed':'Invalid link' ?></h1><p><?= $ok?'You will no longer receive this follow-up sequence.':'Please check your unsubscribe link.' ?></p></div></main></body></html>
